import{_ as a,o as t,c as b,j as r,a as n,a1 as p}from"./chunks/framework.Bp7r_-XI.js";const S=JSON.parse('{"title":"二重幻影","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/1.血统与训练/5.通用类/二重幻影.md","filePath":"4.资源分区/1.血统与训练/5.通用类/二重幻影.md"}'),s={name:"4.资源分区/1.血统与训练/5.通用类/二重幻影.md"};function o(d,e,l,_,i,c){return t(),b("div",null,[...e[0]||(e[0]=[r("h1",{id:"二重幻影",tabindex:"-1"},[n("二重幻影 "),r("a",{class:"header-anchor",href:"#二重幻影","aria-label":'Permalink to "二重幻影"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：新世短歌033")])])],-1),p('<h1 id="二重幻影-1" tabindex="-1">二重幻影 <a class="header-anchor" href="#二重幻影-1" aria-label="Permalink to &quot;二重幻影&quot;">​</a></h1><p>二重幻影<br> 魔幻本质<br> 描述：二重幻影有很多名字，幻身灵，二重身，画皮，都是这个魔物种族在各个文明中的称呼。它们其实是一种脆弱的魔物种族，甚至比起一般的人类更为弱小，只是它们天生具有的变化能力能够让它们变化成与他人相同的外貌，借机混入各个种群之间，欺骗其它生命获取生存的空间，这也是为何各个文明中都有完全与他人外貌相同的非人生物的诡异传说。</p><p>D级：幼体<br> D+600<br> 描述：最弱小的二重幻影也有改变自身外观的能力，它们相较于其它种族更弱且因外貌缘故更容易被敌视，故此天然就具备着伪装自己的本能。<br> 特性：【无面】【幻身】【假意】<br> 【无面】：购买该血统后，你的真实姿态将转变为骇人的魔物，五官、毛发、和外在性征将彻底消失，脸部仅在双眼和口部有渗人的圆孔；这种改变仅会导致外观变化，不代表你真的失去了五感和性征，与人类无异的体格搭配完全无法被称之为人类的脸庞，将会引起所有目睹真实面貌者的恐怖谷反应，所有目睹二重幻影真容者会立即下降二级好感（可以此降低至极端）<br> 此时，你的生物类型在进行判断时将会被视为【魔物】，这是一种特殊的【野兽】类型。</p><p>【幻身】：二重幻影最核心的能力便是【幻身】，你可以将自己的外貌（主要是头部、穿着）变化为任何一个曾见过的人形生物、衣物的模样，但不会改变自身的体形和体积，也没法模仿性别，这是一个D变形来源的伪装效果，这种变化的柔韧性使得二重幻影的肉体不会因伤势而自然恶化。<br> 另一种使用方法是，二重幻影可以随时模糊自己的存在，并将自身与周遭环境进行贴合，这是一种魔幻本质的弱反侦测特性，最低只能以此降低至模糊定位。<br> 为了保证自己在对应族群中的生存，二重幻影具有一定的思维影响能力，可以在和人单独交涉时进行一次额外的/单独的哄骗检定，并对对方造成无支线的影响心灵来源思维暗示效果，以意志豁免，心灵暗示通常是让人相信变成某人朋友模样的自己就是他的朋友，相信一个物件并不具备的价值等小小的谎言，这个效果可以在进行使用哄骗专业的非战斗检定时附带；直到被欺骗者得到其他人的提醒才会意识到不对，这种能力通常被用于二重幻影对自身所变化外貌的原主的亲友进行依次欺骗，并以此让他人认为原主才是那个伪装之物。</p><p>C级：魔物<br> C+1200<br> 描述：更成熟的二重幻影可以完美地改变自身的形态，并且深谙伪装之道。<br> 特性：【幻身-提升】<br> 【幻身】：最为核心的能力得到了提升，如今你可以完全将外形改变为曾遭遇过的另一个人，包括对方的五官、声音、性别、衣着等等，可以模拟出对应的性征但不会直接改变性别，肢体的数量不会发生改变，体积可以增加或减少至多1点，这是C级变形来源的伪装效果。<br> 伪装的能力也得到了提升，如今，幻身提供的环境伪装能力提升为C级魔幻本质的反侦测，并且可以彻底隐藏行踪，在没被侦测到的情况下不会被定位，你可以自由关闭这一能力，出现在他人面前。</p><p>B级：高阶<br> B+2400<br> 描述：高阶二重幻影是二重幻影中的上位种，数量相对稀少，这些高级的伪装者相比起一般的二重幻影，其肉体的自由度甚至可以达到基因级别的伪装，到达这一阶层的二重幻影彻底无需担忧生存问题，它们甚至可以无忧无虑地穿梭在各个种族之间。<br> 特性：【幻身-提升】<br> 【幻身】：高阶二重幻影是二重幻影的上位种，可以彻底变化自己的外形，这包括改变肉体的性状，模仿基因、气质、气息等内在，可以直接改变自身性别并具有对应性征，可以让体积在自身基础上增大或减小至多5点，这不会影响生命值上限，此时，若在幻身变化状态下判断高阶二重幻影的生物类型，则判断为与变化的生物一致，这是一个B级别、变形来源的伪装效果。除此之外，它们的行动力也不不容小觑，额外具有仅能用于转化移动动作的额外2AP，并且在哄骗专业相关的检定上具有额外的1点附加成功。<br> （顺带一提：你确实可以变成非人物种或多肢体物种，但只能模仿肢体动作和行为，并不会真的获得更多肢体、攻击方式和对应能力）<br> 伪装也因此提升为B级魔幻本质的反侦测，同时，高阶二重幻影还会获得更加强大的心灵影响能力，不只是暗示，你在战斗外与人单独交涉时可以进行一次哄骗检定，对方以意志豁免，若对方豁免失败，则其会被你短暂地控制思维，可以接受由你提出的，违背其基本价值观的行为，包括但不限于相信你是真的家人并一起抵制原主、坚信可以在某个地方找到宝物、相信你是某个国家的使臣并放行等等；在此过程中被控制者一旦遭受生命危险，或者要求严重违反其价值观、要求其攻击队友等违反公序良俗与常识的行为后，思维控制便会自动解除。这是一个B级别影响心灵来源的思维控制效果。</p><p>A级：异形种<br> A+4800<br> 描述：异形种是二重幻影中最为稀少的一类存在，和高阶二重幻影明确作为上位种存在不同的是，异形种的力量要远远高于的二重幻影甚至高阶二重幻影，甚至到了被怀疑是全新物种的情况。<br> 特性：【幻身-提升】<br> 【幻身】：在原本幻身效果的基础上，变形的来源提升为A级，你现在可以做到就连灵魂层面都能与这幅幻身的原主完全一致，体积方面，基于自身的体积，至多可以向上增大或缩小自身体积上限提升至20，但不会带来额外的生命上限。<br> 伪装方面异形种已经可以做到完全将自身融入周遭环境，提升为A级魔幻本质的反侦测。<br> 思维控制的来源提升为A级，如今可以对被控制者下达无视道德和社会底线的、不涉及自身安危的任何事，虽然不能直接令其自杀，但是被控制者会无视间接性的死局。<br> 除此之外，异形种相比起其他二重幻影拥有更加灵活的行动方式，它们的变形能力甚至可以将自身变化到另一个空间点位，其具有A级变形来源的传送移动能力，并且具有仅能用于转化为标准动作的4AP。</p><p>S级：论外种<br> S+9600<br> 描述：仅存在于理论上的极端个体，凌驾于所有二重幻影之上的物种，别称为“无害的魔王种”、“从古至今的唯一个体”、“无形之形”等，可能存在于任何地点、城市、家庭、国家乃至大陆，或许在这一个百年只是一个人类，下一个千年是一棵不断生长的参天古树，下一个万年是无人能敌的庞然巨兽。<br> 这个理论上存在的个体可以变化成任何事物，从微小到一粒石子，到庞然似一头巨兽，其可以是任何生物、非生物，内在如此，甚至灵魂也是如此。<br> 故此，该个体很难理解什么是真正的“自我”，也就不会真正的存在该个体本身了。<br> 特性：【无面-提升】【幻身-提升】<br> 【无面】：你的真实姿态骇人到完全无法被世间万物所接受、理解，任何直接目睹你真容的生物如今会立即降低4级好感（可以此降低至极端）。<br> 你将额外被视为【神话生物】。<br> 【幻身】：如今，你的变形来源提升为S级，甚至可以变化自身的物质，可以直接将自身转变为草木山石、飞禽走兽甚至金银铜铁，你可以变化为不存在生命的物体，你的体积至多可以向上增加至300，额外的体积不会带来生命上限，亦可向下减少至八分之一。<br> 魔幻本质的反侦测提升为S级，如今，只要你进行伪装，就几乎不会被世间万物所察觉。<br> 思维控制的来源提升为S级，受到影响者的思维将被完全控制，并在意识上获得了全新的能力，只要你愿意，你可以仅凭一眼，无需检定，立即知晓被你思维控制的生物内心中的所思所想，这是一个S级影响心灵来源的读心效果。<br> 传送移动的来源提升为S级，并额外具有S级的异空间和即死免疫。<br> 同时，每场影片一次，当你死亡时，可以立即在尸体旁边复活，你可以任选一个曾变形过的姿态并以该姿态重获生命。这是一个S级、变形来源的复活效果</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',10)])])}const f=a(s,[["render",o]]);export{S as __pageData,f as default};
